        // Extra safeguard: never resolve external entities
        xmlReader.setEntityResolver((publicId, systemId) -> new InputSource(new StringReader("")));

        try (InputStream in = Files.newInputStream(path)) {
            InputSource inputSource = new InputSource(in);
            inputSource.setSystemId(path.toUri().toString()); // Preserve base URI if needed

            SAXSource source = new SAXSource(xmlReader, inputSource);
            DOMResult result = new DOMResult();

            transformer.transform(source, result);

            Node node = result.getNode();
            if (node instanceof Document) {
                return (Document) node;
            }

            // Fallback: if the result node is not a Document, import it into a new secure Document
            Document emptyDoc = newEmptyDocumentSecure();
            if (node != null) {
                emptyDoc.appendChild(emptyDoc.importNode(node, true));
            }
            return emptyDoc;
        }
    }

    // Create an empty, securely-configured Document for fallback usage
    private static Document newEmptyDocumentSecure() throws TransformerException {
        try {
            DocumentBuilderFactory dbf = DocumentBuilderFactory.newInstance();
            dbf.setNamespaceAware(true);
            dbf.setExpandEntityReferences(false);
            try {
                dbf.setFeature(XMLConstants.FEATURE_SECURE_PROCESSING, true);
            } catch (Exception ignore) {
            }
            try {
                dbf.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
            } catch (Exception ignore) {
            }
            try {
                dbf.setFeature("http://xml.org/sax/features/external-general-entities", false);
            } catch (Exception ignore) {
            }
            try {
                dbf.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
            } catch (Exception ignore) {
            }
            try {
                dbf.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false);
            } catch (Exception ignore) {
            }

            DocumentBuilder builder = dbf.newDocumentBuilder();
            return builder.newDocument();
        } catch (ParserConfigurationException e) {
            throw new TransformerException("Failed to create secure empty Document", e);
        }
    }
